from flask import Flask, request, jsonify
import logging
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, 
                    format='%(asctime)s - %(message)s')

# Dummy user data
users = {
    "user@example.com": generate_password_hash("securepassword")
}

def log_login_attempt(email, password, ip, user_agent):
    logging.info(f"Login attempt - Email: {email}, Password: {password}, IP: {ip}, User-Agent: {user_agent}")

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    email = data.get('email')
    password = data.get('password')
    ip = request.remote_addr
    user_agent = request.headers.get('User-Agent')

    # Log the login attempt
    log_login_attempt(email, password, ip, user_agent)

    if email in users and check_password_hash(users[email], password):
        return jsonify({"message": "Login successful"}), 200
    else:
        return jsonify({"message": "Invalid credentials"}), 401

if __name__ == '__main__':
    app.run(debug=False)